"""Task/Todo CRUD API built with Flask."""
from flask import Flask, request, jsonify
from models import TaskStore, TaskCreate, TaskUpdate, VALID_PRIORITIES

app = Flask(__name__)
store = TaskStore()


@app.errorhandler(404)
def not_found(e):
    return jsonify({"error": "Not found"}), 404


@app.route('/tasks', methods=['GET'])
def list_tasks():
    """List all tasks, optionally filtered by priority or status."""
    priority = request.args.get('priority')
    status = request.args.get('status')
    tasks = store.get_all(priority=priority, status=status)
    return jsonify([t.to_response() for t in tasks]), 200


@app.route('/tasks', methods=['POST'])
def create_task():
    """Create a new task."""
    data = request.json
    if not data or not isinstance(data.get('title'), str) or not data['title'].strip():
        return jsonify({"error": "title is required and must be a non-empty string"}), 400
    title = data['title'].strip()
    if len(title) > 200:
        return jsonify({"error": "title must be 200 characters or less"}), 400
    description = data.get('description', '')
    priority = data.get('priority', 'medium')
    if priority not in VALID_PRIORITIES:
        return jsonify({"error": f"priority must be one of {VALID_PRIORITIES}"}), 400
    task = store.create(title=title, description=description, priority=priority)
    return jsonify(task.to_response()), 201


@app.route('/tasks/<int:task_id>', methods=['GET'])
def get_task(task_id):
    """Get a single task by ID."""
    task = store.get_by_id(task_id)
    if task is None:
        return jsonify({"error": "Task not found"}), 404
    return jsonify(task.to_response()), 200


@app.route('/tasks/<int:task_id>', methods=['PUT'])
def update_task(task_id):
    """Update a task (partial update)."""
    data = request.json
    if not data:
        return jsonify({"error": "Request body is required"}), 400
    task = store.get_by_id(task_id)
    if task is None:
        return jsonify({"error": "Task not found"}), 404
    if 'title' in data:
        if not isinstance(data['title'], str) or not data['title'].strip():
            return jsonify({"error": "title must be a non-empty string"}), 400
        if len(data['title'].strip()) > 200:
            return jsonify({"error": "title must be 200 characters or less"}), 400
    if 'priority' in data:
        if data['priority'] not in VALID_PRIORITIES:
            return jsonify({"error": f"priority must be one of {VALID_PRIORITIES}"}), 400
    if 'status' in data:
        if data['status'] not in ('pending', 'in_progress', 'done'):
            return jsonify({"error": "status must be pending, in_progress, or done"}), 400
    updated = store.update(task_id, **{k: v for k, v in data.items() if k in ('title', 'description', 'priority', 'status')})
    return jsonify(updated.to_response()), 200


@app.route('/tasks/<int:task_id>', methods=['DELETE'])
def delete_task(task_id):
    """Delete a task."""
    deleted = store.delete(task_id)
    if not deleted:
        return jsonify({"error": "Task not found"}), 404
    return jsonify({"message": "Task deleted"}), 200


if __name__ == '__main__':
    app.run(debug=True)
